INSERT INTO `stories` VALUES (1,'Hoa Sơn Tái Khởi','','Đệ tử đời thứ 13 của Đại Hoa Sơn Phái, Mai Hoa Kiếm Tôn - Thanh Minh, người đã liều mình cùng chết với Thiên Ma, kết thúc một thời đại đen tối của võ lâm trung nguyên. Chuyển sinh sau 100 năm với một thân xác nhỏ bé, Thanh Minh nhận ra rằng Hoa Sơn Phái lẫy lừng năm xưa giờ chỉ còn là một môn phái nhỏ bé hoang tàn. Với kí ức và những môn tuyệt học thất truyền từ kiếp trước, Thanh Minh quyết tâm tái khởi Hoa Sơn Phái một lần nữa!','uploads/1774689776032_image-101.jpg','active','2026-03-28 09:22:56'),(2,'Hóa Thân Thành Mèo','','Kaiden - Một người dùng có khả năng bí ẩn ẩn giấu bên trong cơ thể của một con mèo đường phố. Anh ta sau đó được Jiwoo nhặt lên sau khi bị thương sau một trận chiến với người dùng khả năng khác. Anh ta có một tính cách bướng bỉnh và hách dịch. Jiwoo - một cậu học sinh trung học năng động và hay nói chuyện, yêu mèo. Anh ấy rất tốt bụng và dường như cũng có một khả năng đặc biệt.','uploads/1774703315966_9129172696.png','active','2026-03-28 13:07:42'),(3,'Tôi Thăng Cấp Một Mình','Jang Sung Lak','Theo chân Sung JinWoo trên hành trình từ \"thợ săn kém cỏi\" đến \"thợ săn hạng S mạnh nhất thế giới\". (có 1 tí Saitama với 1 tí The gamer, bạn nào thích 2 bộ này xin mời nhảy hố =)))','uploads/1774703906310_4816257067.jpg','active','2026-03-28 13:18:26'),(4,'Ma Vương Như Ta Mới Chuẩn','MIDNIGHT STUDIO','Ta ngoan ngoãn làm theo từng điều trong “Giáo Lý Chuẩn Ma Vương”… rồi bị bọn dũng sĩ giết quách.\r\nBảo ta với cái tháp của ta là “bãi săn thiết kế riêng cho dũng sĩ” á?\r\n\r\nNhờ quay lại quá khứ mà có thêm một cơ hội sống, cái thứ “giáo lý ma vương chết tiệt” đó cho lũ orc xơi đi cho rồi!\r\n\r\nHành trình sống sót với tư cách Ma Vương của thằng ma vương đầu đất Berje bắt đầu từ đây!','uploads/1774704607057_7445112595.jpg','active','2026-03-28 13:30:07');
/*!40000 ALTER TABLE `stories` ENABLE KEYS */;
UNLOCK TABLES;

